import React, { useState } from "react";
import { FaHome, FaUser, FaCog, FaBars, FaTimes } from "react-icons/fa";
import "./dashboardhome.css";

const clients = [
  {
    id: 1,
    name: "Sahar B.",
    email: "sahar@example.com",
    role: "Admin",
    image: "https://randomuser.me/api/portraits/women/1.jpg"
  },
  {
    id: 2,
    name: "Mehdi T.",
    email: "mehdi@example.com",
    role: "Client",
    image: "https://randomuser.me/api/portraits/men/2.jpg"
  },
  {
    id: 3,
    name: "Leila K.",
    email: "leila@example.com",
    role: "Business",
    image: "https://randomuser.me/api/portraits/women/3.jpg"
  }
];

const DashboardHome = () => {
  const [isOpen, setIsOpen] = useState(true);

  return (
    <div className="dashboard-container">
      {/* Sidebar */}
      <div className={`sidebar ${isOpen ? "open" : "closed"}`}>
        <button className="toggle-btn" onClick={() => setIsOpen(!isOpen)}>
          {isOpen ? <FaTimes /> : <FaBars />}
        </button>
        <ul>
          <li>
            <FaHome /> {isOpen && <span>Home</span>}
          </li>
          <li>
            <FaUser /> {isOpen && <span>Profile</span>}
          </li>
          <li>
            <FaCog /> {isOpen && <span>Settings</span>}
          </li>
        </ul>
      </div>

      {/* Contenu principal */}
      <div className="dashboard-content">
        <h1>Dashboard Home</h1>
        <p>Bienvenue sur votre tableau de bord.</p>

        {/* Tableau des clients et business */}
        <div className="table-container">
          <h2>Liste des Clients & Business</h2>
          <table>
            <thead>
              <tr>
                <th>Image</th>
                <th>Nom</th>
                <th>Rôle</th>
                <th>Adresse Mail</th>
              </tr>
            </thead>
            <tbody>
              {clients.map((client) => (
                <tr key={client.id}>
                  <td><img src={client.image} alt={client.name} /></td>
                  <td>{client.name}</td>
                  <td>{client.role}</td>
                  <td>{client.email}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default DashboardHome;
